// BatchAnalysis.js - FINAL IMPLEMENTATION
import React, { useState, useEffect } from "react";
import "./BatchAnalysis.css"; // Import the custom CSS

// Helper function to format numbers as currency (INR Lakhs)
const formatCurrencyLakhs = (value) => {
  if (typeof value !== 'number' || isNaN(value)) return 'N/A';
  return `₹${(value / 100000).toFixed(1)}L`;
};

// Helper function to format large numbers as currency (INR)
const formatCurrency = (value) => {
  if (typeof value !== 'number' || isNaN(value)) return 'N/A';
  return `₹${value.toLocaleString('en-IN', { maximumFractionDigits: 0 })}`;
};

function BatchAnalysis({ onFileChange, onAnalyze, loading, results, selectedFile }) {
  // We use the full prediction data (sample_predictions from backend) to render everything
  const [fullPredictions, setFullPredictions] = useState([]);
  const [filteredData, setFilteredData] = useState([]);
  const [filters, setFilters] = useState({
    riskLevels: ['P1: High Risk (>70%)', 'P2: Moderate Risk (31-70%)', 'P3: Low Risk (<=30%)'],
    tenureRange: [0, 200], // Default max range
    ordersRange: [0, 100]  // Default max range
  });
  const [activeTab, setActiveTab] = useState('scorecard');
  const [analyticsData, setAnalyticsData] = useState(null);
  const [businessImpact, setBusinessImpact] = useState(null);
  const [segmentInsights, setSegmentInsights] = useState(null);

  // --- Effect 1: Process and load data from backend results ---
  useEffect(() => {
    if (results && results.full_response) {
      const { analytics_data, business_impact, segment_insights, sample_predictions } = results.full_response;
      
      // The sample_predictions is the core data for display and filtering
      // Map predictions to ensure all necessary fields for filtering are present and numeric
      const processedPredictions = sample_predictions.map(p => ({
        ...p,
        Tenure: parseFloat(p.Tenure),
        OrderCount: parseFloat(p.OrderCount),
        Churn_Probability: parseFloat(p.Churn_Probability),
        DaySinceLastOrder: parseFloat(p.DaySinceLastOrder)
      }));

      setFullPredictions(processedPredictions);
      setAnalyticsData(analytics_data);
      setBusinessImpact(business_impact);
      setSegmentInsights(segment_insights);

      // Determine the dynamic range for the filters based on the loaded data
      const maxTenure = Math.ceil(Math.max(...processedPredictions.map(p => p.Tenure || 0)));
      const maxOrders = Math.ceil(Math.max(...processedPredictions.map(p => p.OrderCount || 0)));

      // Initialize filters with dynamic max values and all risk levels selected
      setFilters(prevFilters => ({
        ...prevFilters,
        tenureRange: [0, maxTenure > 0 ? maxTenure : 200],
        ordersRange: [0, maxOrders > 0 ? maxOrders : 100],
      }));
      
      // Apply initial filters
      applyFilters(processedPredictions, { 
        ...filters,
        tenureRange: [0, maxTenure > 0 ? maxTenure : 200],
        ordersRange: [0, maxOrders > 0 ? maxOrders : 100],
      });
    }
  }, [results]);


  // --- Effect 2: Re-apply filters when filter settings change ---
  useEffect(() => {
    applyFilters(fullPredictions, filters);
  }, [filters, fullPredictions]);


  const handleFileSelect = (e) => {
    if (e.target.files.length > 0) {
      onFileChange(e);
      // Reset all states upon new file selection
      setFullPredictions([]);
      setFilteredData([]);
      setAnalyticsData(null);
      setBusinessImpact(null);
      setSegmentInsights(null);
      setActiveTab('scorecard');
      setFilters({
        riskLevels: ['P1: High Risk (>70%)', 'P2: Moderate Risk (31-70%)', 'P3: Low Risk (<=30%)'],
        tenureRange: [0, 200],
        ordersRange: [0, 100]
      });
    }
  };

  const applyFilters = (data, filterSettings) => {
    let filtered = [...data];
    
    // Safety check for empty data
    if (data.length === 0) {
      setFilteredData([]);
      return;
    }

    // 1. Risk Level Filter
    if (filterSettings.riskLevels.length > 0) {
      filtered = filtered.filter(item => 
        filterSettings.riskLevels.includes(item.Risk_Level)
      );
    }
    
    // 2. Tenure Range Filter
    filtered = filtered.filter(item => 
      (item.Tenure >= filterSettings.tenureRange[0]) && 
      (item.Tenure <= filterSettings.tenureRange[1])
    );

    // 3. Order Count Range Filter
    filtered = filtered.filter(item => 
      (item.OrderCount >= filterSettings.ordersRange[0]) && 
      (item.OrderCount <= filterSettings.ordersRange[1])
    );
    
    setFilteredData(filtered);
  };

  const handleFilterChange = (filterType, value) => {
    // Only update the filters object
    setFilters(prevFilters => ({ ...prevFilters, [filterType]: value }));
  };

  // --- Rendering Functions (Replicating Streamlit Logic) ---

  const renderExecutiveScorecard = () => {
    if (!results || !businessImpact || !fullPredictions.length) return null;

    const totalCustomers = fullPredictions.length;
    const highRiskCount = fullPredictions.filter(p => p.Risk_Level === 'P1: High Risk (>70%)').length;
    const highRiskFilteredCount = filteredData.filter(p => p.Risk_Level === 'P1: High Risk (>70%)').length;
    
    // Use the comprehensive business metrics calculated in the backend (app1.py)
    const { total_potential_loss, roi_retention, segment_breakdown } = businessImpact;
    
    // Re-calculate filtered potential loss for the scorecard
    const avgOrderValueInr = 850;
    const filteredPotentialLoss = filteredData.reduce((sum, p) => sum + (p.Churn_Probability * avgOrderValueInr * (p.OrderCount || 1)), 0);


    return (
      <div className="executive-scorecard">
        <h3>⭐ Executive Scorecard</h3>
        <div className="scorecard-subtitle">
          {results.full_response.data_source === 'simulated' ? 'Demo Data Analysis' : 'Uploaded Data Analysis'} • 
          Processed in {results.full_response.processing_time_seconds?.toFixed(2) || 'N/A'}s
        </div>
        
        <div className="kpi-grid">
          <div className="kpi-card">
            <div className="kpi-title">Total Customers (Filtered)</div>
            <div className="kpi-value">{filteredData.length.toLocaleString()}</div>
          </div>
          
          <div className="kpi-card">
            <div className="kpi-title">High-Risk % (Total)</div>
            <div className="kpi-value">{totalCustomers > 0 ? (highRiskCount/totalCustomers*100).toFixed(1) : 0}%</div>
          </div>
          
          <div className="kpi-card">
            <div className="kpi-title">Potential Revenue Loss (Filtered)</div>
            <div className="kpi-value">{formatCurrencyLakhs(filteredPotentialLoss)}</div>
          </div>
          
          <div className="kpi-card">
            <div className="kpi-title">ROI on Retention</div>
            <div className="kpi-value">{roi_retention?.toFixed(1) || 'N/A'}x</div>
          </div>
        </div>

        {segment_breakdown && (
          <div className="segment-breakdown">
            <h4>📈 Segment Performance Metrics (Total Dataset)</h4>
            <div className="segment-metrics-grid">
              <div className="segment-metric high-risk">
                <h5>🚨 High Risk Segment</h5>
                <p>Customers: {segment_breakdown.high_risk.count.toLocaleString()}</p>
                <p>Avg Probability: {(segment_breakdown.high_risk.avg_probability * 100).toFixed(1)}%</p>
                <p>Potential Loss: {formatCurrency(segment_breakdown.high_risk.potential_loss)}</p>
              </div>
              <div className="segment-metric medium-risk">
                <h5>⚠️ Medium Risk Segment</h5>
                <p>Customers: {segment_breakdown.medium_risk.count.toLocaleString()}</p>
                <p>Avg Probability: {(segment_breakdown.medium_risk.avg_probability * 100).toFixed(1)}%</p>
                <p>Potential Loss: {formatCurrency(segment_breakdown.medium_risk.potential_loss)}</p>
              </div>
              <div className="segment-metric low-risk">
                <h5>✅ Low Risk Segment</h5>
                <p>Customers: {segment_breakdown.low_risk.count.toLocaleString()}</p>
                <p>Avg Probability: {(segment_breakdown.low_risk.avg_probability * 100).toFixed(1)}%</p>
                <p>Potential Loss: {formatCurrency(segment_breakdown.low_risk.potential_loss)}</p>
              </div>
            </div>
          </div>
        )}

        {highRiskFilteredCount > 0 && (
          <div className="critical-insights">
            <h4>🎯 Critical Business Insights (Filtered)</h4>
            <p>
              The <strong>{highRiskFilteredCount} high-risk customers</strong> in the current view account for a potential loss of{' '}
              <strong>{formatCurrency(filteredPotentialLoss)}</strong>.
              Immediate intervention is recommended for this segment.
            </p>
            <div className="insight-actions">
              <button className="insight-btn primary">🚀 Launch Retention Campaign</button>
              <button className="insight-btn secondary">📞 Schedule Executive Review</button>
            </div>
          </div>
        )}
      </div>
    );
  };

  const renderSegmentCard = (riskLevel, label, color, icon) => {
    // Filter the currently visible data based on the risk level
    const segmentData = filteredData.filter(item => item.Risk_Level === label);
    if (!segmentData.length) return (
      <div className="segment-card no-data">
        <div className="segment-title" style={{ color }}>{icon} {label} (0 Customers)</div>
        <div className="download-btn disabled">📥 Download CSV (0 Records)</div>
      </div>
    );

    const count = segmentData.length;
    const avgChurn = (segmentData.reduce((sum, item) => sum + item.Churn_Probability, 0) / count) * 100;
    const avgRecency = segmentData.reduce((sum, item) => sum + (item.DaySinceLastOrder || 0), 0) / count;
    const avgOrders = segmentData.reduce((sum, item) => sum + (item.OrderCount || 0), 0) / count;

    // Use recommendations from the backend's segment_insights
    const recData = segmentInsights?.[label];
    let recommendations = recData?.recommendations || [];
    let recClass = '';
    let recTitle = '';
    
    if (riskLevel === 'High') {
      recTitle = "CRITICAL INTERVENTION";
      recClass = 'segment-recommendation-high';
    } else if (riskLevel === 'Medium') {
      recTitle = "PROACTIVE ENGAGEMENT";
      recClass = 'segment-recommendation-medium';
    } else { // Low Risk
      recTitle = "LOYALTY MAXIMIZATION";
      recClass = 'segment-recommendation-low';
    }

    // Prepare CSV download data (only filtered data is downloaded)
    const csvContent = [
      'CustomerID,Risk_Level,Churn_Probability,Tenure,OrderCount,CashbackAmount,DaySinceLastOrder,SatisfactionScore',
      ...segmentData.map(row => `${row.CustomerID || 'N/A'},"${row.Risk_Level}",${(row.Churn_Probability * 100).toFixed(2)}%,${row.Tenure},${row.OrderCount},${row.CashbackAmount},${row.DaySinceLastOrder},${row.SatisfactionScore}`)
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);

    return (
      <div className={`segment-card segment-header-${riskLevel.toLowerCase()}`}>
        <div className="segment-header">
          <div className="segment-title" style={{ color }}>
            {icon} {label} ({count} Customers)
          </div>
          <span className="segment-priority">Priority: {riskLevel}</span>
        </div>
        
        <div className="segment-metrics">
          <div className="metric">
            <div className="metric-label">Avg. Churn Prob.</div>
            <div className="metric-value">{avgChurn.toFixed(1)}%</div>
          </div>
          <div className="metric">
            <div className="metric-label">Avg. Days Inactive</div>
            <div className="metric-value">{avgRecency.toFixed(1)} days</div>
          </div>
          <div className="metric">
            <div className="metric-label">Avg. Orders</div>
            <div className="metric-value">{avgOrders.toFixed(1)}</div>
          </div>
        </div>

        <div className={`segment-recommendations ${recClass}`}>
          <div className="recommendation-title" style={{ color }}>{recTitle}</div>
          <ul>
            {recommendations.map((rec, index) => (
              <li key={index} dangerouslySetInnerHTML={{ __html: rec }}></li>
            ))}
          </ul>
        </div>

        <a 
          href={url} 
          download={`${riskLevel.toLowerCase()}_risk_customers_${new Date().toISOString().split('T')[0]}.csv`}
          className="download-btn"
        >
          📥 Download {riskLevel} Segment CSV ({count} Records)
        </a>
      </div>
    );
  };

  const renderAnalyticsCharts = () => {
    if (!analyticsData) return null;

    const { risk_distribution, probability_distribution, feature_analysis, value_risk_analysis } = analyticsData;
    const totalCustomers = fullPredictions.length;

    // --- Risk Distribution Chart ---
    const renderRiskDistributionChart = () => {
      const { labels, values, colors } = risk_distribution;
      
      return (
        <div className="chart-container">
          <h4>📊 Customer Distribution by Risk Level (Total: {totalCustomers})</h4>
          <div className="bar-chart">
            {labels.map((label, index) => {
              const count = values[index] || 0;
              const percentage = ((count / totalCustomers) * 100).toFixed(1);
              return (
                <div key={index} className="bar-item">
                  <div className="bar-label">{label}</div>
                  <div className="bar-track">
                    <div 
                      className="bar-fill" 
                      style={{ 
                        width: `${percentage}%`,
                        backgroundColor: colors[index]
                      }}
                    >
                      <span className="bar-value">{count} ({percentage}%)</span>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      );
    };

    // --- Probability Distribution Chart (Histogram) ---
    const renderProbabilityDistribution = () => {
      const { bins, counts } = probability_distribution;
      const maxCount = Math.max(...counts, 1);

      return (
        <div className="chart-container">
          <h4>📈 Distribution of Churn Probabilities</h4>
          <div className="histogram">
            {bins.map((bin, index) => (
              <div key={index} className="histogram-bar">
                <div 
                  className="histogram-fill"
                  style={{ 
                    height: `${(counts[index] / maxCount) * 100}%`,
                  }}
                >
                  <span className="histogram-count">{counts[index]}</span>
                </div>
                <div className="histogram-label">{bin}</div>
              </div>
            ))}
          </div>
        </div>
      );
    };

    // --- Feature Analysis (Table, replicating Streamlit box plots with summary) ---
    const renderFeatureAnalysis = () => {
      const features = ['Tenure', 'CashbackAmount', 'DaySinceLastOrder'];
      
      return features.map(feature => {
        const featureData = feature_analysis[feature];
        if (!featureData || featureData.length === 0) return null;
  
        // Find the full range across all risk levels for min/max
        const allValues = fullPredictions.map(p => p[feature]).filter(v => v !== undefined && v !== null);
        const overallMin = Math.min(...allValues);
        const overallMax = Math.max(...allValues);
  
        return (
          <div key={feature} className="chart-container">
            <h4>📋 {feature} Distribution by Risk Level</h4>
            <div className="stats-table-wrapper">
              <table>
                <thead>
                  <tr>
                    <th>Risk Level</th>
                    <th>Count</th>
                    <th>Avg ({feature})</th>
                    <th>Median</th>
                    <th>Range (Min-Max)</th>
                  </tr>
                </thead>
                <tbody>
                  {featureData.map((stat, index) => (
                    <tr key={index}>
                      <td className={`risk-label-cell ${stat.risk_level.split(':')[0].toLowerCase()}`}>{stat.risk_level.split(':')[0]}</td>
                      <td>{fullPredictions.filter(p => p.Risk_Level === stat.risk_level).length.toLocaleString()}</td>
                      <td>{stat.mean?.toFixed(1) || 'N/A'}</td>
                      <td>{stat.median?.toFixed(1) || 'N/A'}</td>
                      <td>{`${stat.min?.toFixed(1) || 'N/A'} - ${stat.max?.toFixed(1) || 'N/A'}`}</td>
                    </tr>
                  ))}
                  <tr className="overall-row">
                    <td>Overall</td>
                    <td>{fullPredictions.length.toLocaleString()}</td>
                    <td>{(allValues.reduce((a, b) => a + b, 0) / allValues.length).toFixed(1)}</td>
                    <td>{overallMin.toFixed(1)} - {overallMax.toFixed(1)}</td>
                  </tr>
                </tbody>
              </table>
            </div>
          </div>
        );
      });
    };

    // --- Customer Value vs Churn Risk Analysis (Summary, replicating Streamlit scatter plot) ---
    const renderValueRiskAnalysis = () => {
      const riskGroups = {
        high: value_risk_analysis.filter(item => item.riskLevel.includes('High')),
        medium: value_risk_analysis.filter(item => item.riskLevel.includes('Moderate')),
        low: value_risk_analysis.filter(item => item.riskLevel.includes('Low'))
      };
      
      const calculateStats = (group) => {
        if (group.length === 0) return { count: 0, avgValue: 0, avgRisk: 0 };
        const avgValue = group.reduce((sum, item) => sum + item.customerValue, 0) / group.length;
        const avgRisk = group.reduce((sum, item) => sum + item.churnProbability, 0) / group.length;
        return {
          count: group.length,
          avgValue,
          avgRisk
        };
      };

      const highStats = calculateStats(riskGroups.high);
      const mediumStats = calculateStats(riskGroups.medium);
      const lowStats = calculateStats(riskGroups.low);

      return (
        <div className="chart-container">
          <h4>💰 Churn Risk vs Customer Value Analysis (Scatter Summary)</h4>
          <div className="scatter-summary">
            <div className="risk-group high-risk">
              <h5>🚨 High Risk Customers</h5>
              <p>Count: {highStats.count.toLocaleString()}</p>
              <p>Avg Value: {formatCurrency(highStats.avgValue)}</p>
              <p>Avg Risk: {highStats.avgRisk.toFixed(1)}%</p>
            </div>
            <div className="risk-group medium-risk">
              <h5>⚠️ Medium Risk Customers</h5>
              <p>Count: {mediumStats.count.toLocaleString()}</p>
              <p>Avg Value: {formatCurrency(mediumStats.avgValue)}</p>
              <p>Avg Risk: {mediumStats.avgRisk.toFixed(1)}%</p>
            </div>
            <div className="risk-group low-risk">
              <h5>✅ Low Risk Customers</h5>
              <p>Count: {lowStats.count.toLocaleString()}</p>
              <p>Avg Value: {formatCurrency(lowStats.avgValue)}</p>
              <p>Avg Risk: {lowStats.avgRisk.toFixed(1)}%</p>
            </div>
          </div>
        </div>
      );
    };

    return (
      <div className="analytics-view">
        <h3>📈 Visual Analytics & Insights (Total Dataset)</h3>
        
        <div className="charts-grid">
          <div className="chart-row full-width">{renderRiskDistributionChart()}</div>
          <div className="chart-row full-width">{renderProbabilityDistribution()}</div>
          
          {/* Feature Analysis */}
          <div className="chart-row">{renderFeatureAnalysis()}</div>
          
          <div className="chart-row full-width">{renderValueRiskAnalysis()}</div>
        </div>
      </div>
    );
  };
  
  // --- Main Render ---

  // Check if results are loaded before rendering the dashboard
  const isResultsLoaded = fullPredictions.length > 0 && businessImpact;

  // Find dynamic max for filters if data is loaded
  const dynamicMaxTenure = fullPredictions.length > 0 ? Math.ceil(Math.max(...fullPredictions.map(p => p.Tenure))) : 200;
  const dynamicMaxOrders = fullPredictions.length > 0 ? Math.ceil(Math.max(...fullPredictions.map(p => p.OrderCount))) : 100;

  return (
    <div className="batch-analysis">
      <div className="analysis-container">
        
        {/* File Upload/Action Section */}
        <div className="section-card">
          <div className="file-upload-area">
            <input
              type="file"
              accept=".csv"
              onChange={handleFileSelect}
              className="file-input"
              id="batch-file"
            />
            <label htmlFor="batch-file" className="file-label">
              <span className="btn-icon">📎</span>
              Choose CSV File
            </label>
            
            {selectedFile && (
              <div className="file-info">
                <span className="file-success">✅</span>
                <div className="file-details">
                  <strong>{selectedFile.name}</strong>
                  <span>{(selectedFile.size / 1024).toFixed(1)} KB</span>
                </div>
              </div>
            )}
            
            <div className="file-requirements">
              <p><strong>Required format:</strong> CSV with customer features (Tenure, OrderCount, CashbackAmount, etc.).</p>
              <p><small>Click **Analyze Customer Data** without uploading to use **Demo Data**.</small></p>
            </div>
          </div>

          <div className="action-buttons-bottom">
            <button 
              className="action-btn primary" 
              onClick={onAnalyze} 
              disabled={loading}
            >
              {loading ? (
                <>
                  <div className="spinner"></div>
                  Processing Batch Analysis...
                </>
              ) : (
                <>
                  <span className="btn-icon">🚀</span>
                  Analyze Customer Data
                </>
              )}
            </button>
          </div>
        </div>

        {/* Results Dashboard */}
        {isResultsLoaded && (
          <div className="batch-results">
            <div className="results-header">
              <h3>📊 Batch Analysis Results</h3>
              <div className="results-meta">
                <span className="data-source">
                  Source: {results.full_response.data_source === 'simulated' ? 'Demo Data' : 'Uploaded File'}
                </span>
                <span className="processing-time">
                  Processed in {results.full_response.processing_time_seconds?.toFixed(2) || 'N/A'}s
                </span>
                <span className="model-used">
                  Model: {results.full_response.model_used === 'ml_model' ? 'Production ML' : 'Smart Logic'}
                </span>
              </div>
            </div>
            
            {/* Filters */}
            <div className="filters-section">
              <h4>🔍 Filter Customer Segments ({filteredData.length.toLocaleString()} of {fullPredictions.length.toLocaleString()} Customers)</h4>
              <div className="filter-grid">
                <div className="filter-group">
                  <label>Risk Level</label>
                  <select 
                    multiple
                    value={filters.riskLevels}
                    onChange={(e) => {
                      const selected = Array.from(e.target.selectedOptions, option => option.value);
                      handleFilterChange('riskLevels', selected);
                    }}
                    className="multi-select"
                    size={4}
                  >
                    <option value="P1: High Risk (>70%)">🚨 High Risk</option>
                    <option value="P2: Moderate Risk (31-70%)">⚠️ Moderate Risk</option>
                    <option value="P3: Low Risk (<=30%)">✅ Low Risk</option>
                  </select>
                </div>
                
                <div className="filter-group">
                  <label>Tenure Range (Months)</label>
                  <div className="range-inputs">
                    <input 
                      type="number" 
                      value={filters.tenureRange[0]}
                      onChange={(e) => handleFilterChange('tenureRange', [Math.max(0, parseInt(e.target.value) || 0), filters.tenureRange[1]])}
                      min="0"
                      max={dynamicMaxTenure}
                    />
                    <span>to</span>
                    <input 
                      type="number" 
                      value={filters.tenureRange[1]}
                      onChange={(e) => handleFilterChange('tenureRange', [filters.tenureRange[0], Math.min(dynamicMaxTenure, parseInt(e.target.value) || 0)])}
                      min="0"
                      max={dynamicMaxTenure}
                    />
                  </div>
                </div>
                
                <div className="filter-group">
                  <label>Order Count Range</label>
                  <div className="range-inputs">
                    <input 
                      type="number" 
                      value={filters.ordersRange[0]}
                      onChange={(e) => handleFilterChange('ordersRange', [Math.max(0, parseInt(e.target.value) || 0), filters.ordersRange[1]])}
                      min="0"
                      max={dynamicMaxOrders}
                    />
                    <span>to</span>
                    <input 
                      type="number" 
                      value={filters.ordersRange[1]}
                      onChange={(e) => handleFilterChange('ordersRange', [filters.ordersRange[0], Math.min(dynamicMaxOrders, parseInt(e.target.value) || 0)])}
                      min="0"
                      max={dynamicMaxOrders}
                    />
                  </div>
                </div>
              </div>
            </div>

            {/* Tabs */}
            <div className="results-tabs">
              <button 
                className={`tab-button ${activeTab === 'scorecard' ? 'active' : ''}`}
                onClick={() => setActiveTab('scorecard')}
              >
                ⭐ Executive Scorecard
              </button>
              <button 
                className={`tab-button ${activeTab === 'segmentation' ? 'active' : ''}`}
                onClick={() => setActiveTab('segmentation')}
              >
                💡 Actionable Segmentation
              </button>
              <button 
                className={`tab-button ${activeTab === 'analytics' ? 'active' : ''}`}
                onClick={() => setActiveTab('analytics')}
              >
                📈 Detailed Analytics
              </button>
            </div>

            {/* Tab Content */}
            <div className="tab-content">
              {activeTab === 'scorecard' && renderExecutiveScorecard()}
              
              {activeTab === 'segmentation' && (
                <div className="segmentation-view">
                  <h3>💡 Actionable Customer Segmentation (Filtered)</h3>
                  <div className="segmentation-grid">
                    {/* Rendered Columns for Streamlit-like layout */}
                    <div className="segment-column">
                      {renderSegmentCard('High', 'P1: High Risk (>70%)', '#ef4444', '🚨')}
                    </div>
                    <div className="segment-column">
                      {renderSegmentCard('Medium', 'P2: Moderate Risk (31-70%)', '#f97316', '⚠️')}
                    </div>
                    <div className="segment-column">
                      {renderSegmentCard('Low', 'P3: Low Risk (<=30%)', '#34d399', '✅')}
                    </div>
                  </div>
                  
                  <div className="download-all-section">
                    <button className="download-all-btn" onClick={() => downloadAllData(fullPredictions)}>
                      📥 Download Complete Analysis CSV ({fullPredictions.length.toLocaleString()} records)
                    </button>
                    <p className="download-note">
                      Includes all customer data with churn predictions and risk levels for CRM import
                    </p>
                  </div>
                </div>
              )}
              
              {activeTab === 'analytics' && renderAnalyticsCharts()}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

// Function to handle the actual full dataset download
const downloadAllData = (data) => {
    if (!data || data.length === 0) return;

    const allData = data.map(item => ({
      ...item,
      Churn_Probability: (item.Churn_Probability * 100).toFixed(2) + '%'
    }));

    // Generate CSV content
    const csvContent = [
      Object.keys(allData[0]).join(','),
      ...allData.map(row => Object.values(row).map(value => {
        // Simple quoting for safety
        if (typeof value === 'string' && (value.includes(',') || value.includes('"') || value.includes('\n'))) {
            return `"${value.replace(/"/g, '""')}"`;
        }
        return value;
      }).join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    
    const a = document.createElement('a');
    a.href = url;
    a.download = `complete_churn_analysis_${new Date().toISOString().split('T')[0]}.csv`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
};

export default BatchAnalysis;
